from dataclasses import dataclass, field
from typing import Any, Callable

@dataclass
class WorldModel:
    """Tracks everything the agent believes about the world."""
    state: dict = field(default_factory=dict)

    def update(self, percept: dict, last_action: str | None) -> None:
        """Update belief state from a new percept and the last action taken."""
        # First apply the effect the last action should have had
        if last_action:
            self._apply_transition(last_action)
        # Then incorporate the new percept (sensors override predictions)
        self.state.update({k: v for k, v in percept.items() if v is not None})

    def _apply_transition(self, action: str) -> None:
        """Transition model: predict how action changes the world."""
        pass  # subclasses define domain-specific transitions

@dataclass
class Rule:
    condition: Callable[[dict], bool]
    action: str

class ModelBasedReflexAgent:
    def __init__(self, model: WorldModel, rules: list[Rule]):
        self.model = model
        self.rules = rules
        self.last_action: str | None = None

    def act(self, percept: dict) -> str:
        # 1. Update internal belief state
        self.model.update(percept, self.last_action)
        # 2. Choose action based on belief state (not raw percept)
        for rule in self.rules:
            if rule.condition(self.model.state):
                self.last_action = rule.action
                return rule.action
        self.last_action = "no-op"
        return "no-op"

# Vacuum cleaner that tracks visited rooms
from dataclasses import dataclass, field
from typing import Callable

@dataclass
class Rule:
    condition: Callable[[dict], bool]
    action: str

class VacuumWorldModel:
    def __init__(self):
        self.state = {
            "location": "A",
            "A_dirty": True,
            "B_dirty": True,
            "visited": set(),
        }

    def update(self, percept: dict, last_action: str | None) -> None:
        # Apply transition from last action
        if last_action == "move_right":
            self.state["location"] = "B"
        elif last_action == "move_left":
            self.state["location"] = "A"
        elif last_action == "clean":
            loc = self.state["location"]
            self.state[f"{loc}_dirty"] = False  # we just cleaned it
        # Update with sensor reading (percept may override prediction)
        if percept.get("dirt") is not None:
            loc = self.state["location"]
            self.state[f"{loc}_dirty"] = percept["dirt"]
        self.state["visited"].add(self.state["location"])

model = VacuumWorldModel()
rules = [
    # Rule 1: clean current room if dirty
    Rule(condition=lambda s: s[f"{s["location"]}_dirty"], action="clean"),
    # Rule 2: move to unvisited or dirty room
    Rule(condition=lambda s: s["location"] == "A" and s["B_dirty"], action="move_right"),
    Rule(condition=lambda s: s["location"] == "B" and s["A_dirty"], action="move_left"),
]

class ModelBasedVacuum:
    def __init__(self):
        self.model = model
        self.rules = rules
        self.last_action = None

    def act(self, percept: dict) -> str:
        self.model.update(percept, self.last_action)
        for rule in self.rules:
            if rule.condition(self.model.state):
                self.last_action = rule.action
                return rule.action
        self.last_action = "idle"
        return "idle"

agent = ModelBasedVacuum()
# Percept: sensor says current room is dirty; other room unknown
print(agent.act({"dirt": True}))   # clean  (A is dirty)
print(agent.act({"dirt": None}))   # move_right (used model to remember B is still dirty)
print(agent.act({"dirt": True}))   # clean  (B is dirty)
print(agent.act({"dirt": None}))   # idle   (model: both rooms now clean)

# Stale belief problem: model drifts from reality over time
from dataclasses import dataclass
from time import monotonic

@dataclass
class TimestampedBelief:
    value: object
    updated_at: float  # monotonic time
    max_age_seconds: float = 30.0  # belief expires after 30s

    @property
    def is_stale(self) -> bool:
        return monotonic() - self.updated_at > self.max_age_seconds

class FreshWorldModel:
    def __init__(self):
        self._beliefs: dict[str, TimestampedBelief] = {}

    def set(self, key: str, value: object, max_age: float = 30.0) -> None:
        self._beliefs[key] = TimestampedBelief(value, monotonic(), max_age)

    def get(self, key: str, default=None):
        belief = self._beliefs.get(key)
        if belief is None or belief.is_stale:
            return default  # expired belief treated as unknown
        return belief.value

    @property
    def state(self) -> dict:
        return {k: b.value for k, b in self._beliefs.items() if not b.is_stale}

# Usage: beliefs about temperature expire after 10 seconds
model = FreshWorldModel()
model.set("temperature", 22.5, max_age=10.0)
print(model.get("temperature"))  # 22.5 (fresh)
# After 10 seconds without a new reading:
# model.get("temperature") returns None → agent must request a reading
